import os
import shlex
from configparser import ConfigParser, NoOptionError
from collections import OrderedDict

# Default encoding
DEFAULT_ENCODING = 'UTF-8'

# Boolean values
TRUE_VALUES = ('y', 'yes', 't', 'true', 'on', '1')
FALSE_VALUES = ('n', 'no', 'f', 'false', 'off', '0')

# Undefined value representation
class Undefined(object):
    def __repr__(self):
        return '<UNDEFINED>'

undefined = Undefined()

class UndefinedValueError(Exception):
    """
    Exception raised when a value is not defined.
    """
    pass

class RepositoryEmpty(object):
    def __init__(self, source='', encoding=DEFAULT_ENCODING):
        pass

    def __contains__(self, key):
        return False

    def __getitem__(self, key):
        return None

class RepositoryIni(RepositoryEmpty):
    """
    Retrieves option keys from .ini files.
    """
    SECTION = 'settings'

    def __init__(self, source, encoding=DEFAULT_ENCODING):
        self.parser = ConfigParser()
        with open(source, encoding=encoding) as file_:
            self.parser.read_file(file_)

    def __contains__(self, key):
        return (key in os.environ or
                self.parser.has_option(self.SECTION, key))

    def __getitem__(self, key):
        try:
            return self.parser.get(self.SECTION, key)
        except NoOptionError:
            raise KeyError(key)

class RepositoryEnv(RepositoryEmpty):
    """
    Retrieves option keys from .env files with fall back to os.environ.
    """
    def __init__(self, source, encoding=DEFAULT_ENCODING):
        self.data = {}

        with open(source, encoding=encoding) as file_:
            for line in file_:
                line = line.strip()
                if not line or line.startswith('#') or '=' not in line:
                    continue
                k, v = line.split('=', 1)
                k = k.strip()
                v = v.strip()
                if len(v) >= 2 and ((v[0] == "'" and v[-1] == "'") or (v[0] == '"' and v[-1] == '"')):
                    v = v[1:-1]
                self.data[k] = v

    def __contains__(self, key):
        return key in os.environ or key in self.data

    def __getitem__(self, key):
        if key in os.environ:
            return os.environ[key]
        elif key in self.data:
            return self.data[key]
        else:
            raise KeyError(key)

class RepositorySecret(RepositoryEmpty):
    """
    Retrieves option keys from files,
    where title of file is a key, content of file is a value
    e.g. Docker swarm secrets
    """

    def __init__(self, source='/run/secrets/'):
        self.data = {}

        try:
            ls = os.listdir(source)
            for file in ls:
                with open(os.path.join(source, file), 'r') as f:
                    self.data[file] = f.read()
        except OSError:
            # Directory doesn't exist or can't be accessed
            pass

    def __contains__(self, key):
        return key in os.environ or key in self.data

    def __getitem__(self, key):
        if key in os.environ:
            return os.environ[key]
        elif key in self.data:
            return self.data[key]
        else:
            raise KeyError(key)

class Config(object):
    """
    Handle .env file format used by Foreman.
    """

    def __init__(self, repository):
        self.repository = repository

    def get(self, option, default=undefined, cast=undefined):
        """
        Return the value for option or default if defined.
        """

        # We can't avoid __contains__ because value may be empty.
        if option in os.environ:
            value = os.environ[option]
        elif option in self.repository:
            value = self.repository[option]
        else:
            if isinstance(default, Undefined):
                raise UndefinedValueError('{} not found. Declare it as envvar or define a default value.'.format(option))

            value = default

        if isinstance(cast, Undefined):
            cast = self._cast_do_nothing
        elif cast is bool:
            cast = self._cast_boolean

        return cast(value)

    def _cast_boolean(self, value):
        """Convert string to boolean"""
        if isinstance(value, bool):
            return value
        value = value.lower()

        if value in TRUE_VALUES:
            return True
        elif value in FALSE_VALUES:
            return False

        raise ValueError("Invalid truth value: " + value)

    @staticmethod
    def _cast_do_nothing(value):
        """Default casting function that does nothing"""
        return value

    def __call__(self, option, default=undefined, cast=undefined):
        """Convenience call to get() method"""
        return self.get(option, default, cast)

class Csv(object):
    """
    Produces a csv parser that return a list of transformed elements.
    """

    def __init__(self, cast=str, delimiter=',', strip=' \t\n\r', post_process=list):
        """
        Parameters:
        cast -- callable that transforms the item just before it's added to the list.
        delimiter -- string of delimiters chars passed to shlex.
        strip -- string of non-relevant characters to be passed to str.strip after the split.
        post_process -- callable to post process all casted values. Default is `list`.
        """
        self.cast = cast
        self.delimiter = delimiter
        self.strip = strip
        self.post_process = post_process

    def __call__(self, value):
        """The actual transformation"""
        if value is None:
            return self.post_process()

        transform = lambda s: self.cast(s.strip(self.strip))

        splitter = shlex.shlex(value, posix=True)
        splitter.whitespace = self.delimiter
        splitter.whitespace_split = True

        return self.post_process(transform(s) for s in splitter)

class Choices(object):
    """
    Allows for cast and validation based on a list of choices.
    """

    def __init__(self, flat=None, cast=str, choices=None):
        """
        Parameters:
        flat -- a flat list of valid choices.
        cast -- callable that transforms value before validation.
        choices -- tuple of Django-like choices.
        """
        self.flat = flat or []
        self.cast = cast
        self.choices = choices or []

        self._valid_values = []
        self._valid_values.extend(self.flat)
        self._valid_values.extend([value for value, _ in self.choices])

    def __call__(self, value):
        transform = self.cast(value)
        if transform not in self._valid_values:
            raise ValueError((
                    'Value not in list: {!r}; valid values are {!r}'
                ).format(value, self._valid_values))
        else:
            return transform

class AutoConfig(object):
    """
    Autodetects the config file and type.

    Parameters
    ----------
    search_path : str, optional
        Initial search path. If empty, the default search path is the
        caller's path.

    """
    SUPPORTED = OrderedDict([
        ('settings.ini', RepositoryIni),
        ('.env', RepositoryEnv),
    ])

    encoding = DEFAULT_ENCODING

    def __init__(self, search_path=None):
        self.search_path = search_path
        self.config = None

    def _caller_path(self):
        """Get the path of the caller"""
        import inspect
        frame = inspect.currentframe()
        try:
            caller_frame = frame.f_back.f_back
            return os.path.abspath(caller_frame.f_code.co_filename)
        finally:
            del frame

    def _find_file(self, path):
        """Recursively search upwards for supported files"""
        if not path:
            path = self._caller_path()

        # Convert to absolute path if needed
        if not os.path.isabs(path):
            path = os.path.abspath(path)

        while True:
            for filename, repo_class in self.SUPPORTED.items():
                full_path = os.path.join(path, filename)
                if os.path.isfile(full_path):
                    return full_path, repo_class

            parent = os.path.dirname(path)
            if parent == path:  # Reached root directory
                break
            path = parent

        return None, None

    def _load(self):
        """Load configuration repository"""
        if self.config is not None:
            return self.config

        source, repo_class = self._find_file(self.search_path)

        if source and repo_class:
            try:
                repo = repo_class(source, encoding=self.encoding)
            except Exception:
                # Fallback to empty repository if file cannot be read
                repo = RepositoryEmpty()
        else:
            # No configuration file found, use empty repository
            repo = RepositoryEmpty()

        self.config = Config(repo)
        return self.config

    def __call__(self, option, default=undefined, cast=undefined):
        """Configuration access interface"""
        return self._load()(option, default, cast)

def strtobool(value):
    """Convert a string to a boolean value."""
    if isinstance(value, bool):
        return value
    value = value.lower()

    if value in TRUE_VALUES:
        return True
    elif value in FALSE_VALUES:
        return False

    raise ValueError("Invalid truth value: " + value)
